/**
 * Todoist tool wrapper generator — task tracking via Todoist REST API.
 *
 * Generates a bash script that wraps curl calls to the Todoist REST API v2.
 * API token comes from TODOIST_API_TOKEN environment variable.
 */

export function generateTodoistTool(): string {
  return `#!/usr/bin/env bash
# todoist — task tracking via Todoist REST API
# Generated by ClawHQ from blueprint config
# Auth header injected by credential proxy — token never in this container.
set -euo pipefail

# Credential proxy injects Authorization header; tool never sees the token.
PROXY="\${CRED_PROXY_URL:?CRED_PROXY_URL not set — credential proxy not configured}"
API="\${PROXY}/todoist"

usage() {
  cat <<'USAGE'
Usage: todoist <command> [args]

Commands:
  list [--project PROJECT]      List active tasks
  add <content> [--project P]   Add a task
  close <id>                    Complete a task
  delete <id>                   Delete a task
  projects                      List projects
  get <id>                      Get task details
USAGE
}

cmd_list() {
  local project="\${1:-}"
  local url="$API/tasks"
  if [ -n "$project" ]; then
    url="$url?project_id=$project"
  fi
  curl -sS "$url"
}

cmd_add() {
  local content="$1"
  local project="\${2:-}"
  local body
  if [ -n "$project" ]; then
    body=$(jq -n --arg c "$content" --arg p "$project" '{content: $c, project_id: $p}')
  else
    body=$(jq -n --arg c "$content" '{content: $c}')
  fi
  curl -sS -X POST -H "Content-Type: application/json" -d "$body" "$API/tasks"
}

cmd_close() {
  local id="$1"
  curl -sS -X POST "$API/tasks/$id/close"
  echo "Closed task: $id"
}

cmd_delete() {
  local id="$1"
  curl -sS -X DELETE "$API/tasks/$id"
  echo "Deleted task: $id"
}

cmd_projects() {
  curl -sS "$API/projects"
}

cmd_get() {
  local id="$1"
  curl -sS "$API/tasks/$id"
}

case "\${1:-}" in
  list)     shift; cmd_list "\${1:-}" ;;
  add)      shift; cmd_add "\${1:?content required}" "\${2:-}" ;;
  close)    shift; cmd_close "\${1:?id required}" ;;
  delete)   shift; cmd_delete "\${1:?id required}" ;;
  projects) cmd_projects ;;
  get)      shift; cmd_get "\${1:?id required}" ;;
  -h|--help|help|"") usage ;;
  *) echo "todoist: unknown command '$1'" >&2; usage >&2; exit 1 ;;
esac
`;
}
